text:
Sorry, I spent too long time.
But I already found out what is the problem, and I just about to send a question to net@.
The mail I sent to net@ and stable@ should be delivered soon.


The following patch stops the continuous recv() error, and it should be required
to handle OOB data, but the first recv() error shouldn't be happened.
I will report this to developer after I could know select() behavior on FreeBSD 8.x is
correct or not. 

--- stone.c.orig        2008-02-05 08:00:00.000000000 +0900
+++ stone.c     2010-05-07 02:05:13.000000000 +0900
@@ -651,6 +651,7 @@
 const int proto_ohttp_d =       0x8000000;     /*           destination */
 const int proto_base_s =       0x10000000;     /* base64 source */
 const int proto_base_d =       0x20000000;     /*        destination */
+const int proto_just_read_oob =        0x40000000;     /* do no set xo now */
 #define command_ihead              0x0100      /* insert header */
 #define command_iheads             0x0200      /* insert header repeatedly */
 #define command_pop                0x0300      /* POP -> APOP conversion */
@@ -6285,13 +6286,15 @@
 #endif
            isset = 1;
        }
-       if (isset)
+       if (isset) {
 #ifdef USE_EPOLL
            ev.events |= EPOLLPRI;
        epoll_ctl(ePollFd, EPOLL_CTL_MOD, sd, &ev);
 #else
-           FdSet(sd, eoutp);
+           if (!(pair->proto & proto_just_read_oob))
+               FdSet(sd, eoutp);
 #endif
+       }
     }
 #ifdef USE_EPOLL
     if (Debug > 7)
@@ -6354,6 +6357,7 @@
     } else if (ready_e) {      /* Out-of-Band Data */
        char buf[1];
        len = recv(sd, buf, 1, MSG_OOB);
+       pair->proto |= proto_just_read_oob;
        if (len == 1) {
            if (opposite) wsd = opposite->sd; else wsd = INVALID_SOCKET;
            if (Debug > 3)
@@ -6492,6 +6496,7 @@
            }
        } else {
            if (len > 0) {
+               pair->proto &= ~proto_just_read_oob;
                int first_flag;
                first_flag = (rPair->proto & proto_first_r);
                if (first_flag) len = first_read(rPair);
